check.command:
awk -v token='acl' '
function trim(s){gsub(/^[[:space:]]+|[[:space:]]+$/,"",s); return s}
/^[[:space:]]*(#|$)/{next}
$1 !~ /^\// && $0 ~ /^[[:space:]]*[A-Za-z][A-Za-z0-9_]*[[:space:]]*=/ {name=$1; sub(/[[:space:]]*=.*/,"",name); expr=$0; sub(/^[^=]*=/,"",expr); rules[name]=trim(expr); next}
$1 ~ /^\// {expr=$NF; gsub(/[[:space:]]*#.*/,"",expr); resolved=(expr in rules)?rules[expr]:expr; if (resolved !~ "(^|[+[:space:]])" token "($|[+[:space:]])") print $0}
' /etc/aide.conf 2>/dev/null
